const fs = require('fs');
const crypto = require('crypto');
const Autumn = require('autumn-js');

// Initialize the Autumn client
// Note: Depending on the specific version of autumn-js, it might require an object like { apiKey: ... }
// or just the string. We'll pass the string as it's common for many SDKs, or fallback to object if needed.
let autumn;
try {
    autumn = new Autumn(process.env.AUTUMN_SECRET_KEY);
} catch (e) {
    autumn = new Autumn({ apiKey: process.env.AUTUMN_SECRET_KEY });
}

async function main() {
    // 1. Generate a unique idempotencyKey using crypto.randomUUID(), or use process.env.IDEMPOTENCY_KEY if set
    const idempotencyKey = process.env.IDEMPOTENCY_KEY || crypto.randomUUID();

    console.log(`Using idempotency key: ${idempotencyKey}`);

    try {
        // 2. Call autumn.customers.track with the required parameters
        const result = await autumn.customers.track({
            customerId: "user_test_001",
            featureId: "api-calls",
            value: 1,
            idempotencyKey: idempotencyKey
        });

        // 3. Save the returned result to /home/user/myproject/track_result.json
        fs.writeFileSync('/home/user/myproject/track_result.json', JSON.stringify(result, null, 2));
        console.log('Usage tracked successfully and result saved to track_result.json.');
    } catch (error) {
        console.error('Error tracking usage:', error);
        process.exit(1);
    }
}

main();

